const b = $json.body || $json;

const onlyDigits = (v) => String(v || '').replace(/\D/g, '');
const rawPhone = onlyDigits(b.phone || b.telefone || '');
let phone_e164 = '';
if (rawPhone.length === 11) phone_e164 = `+55${rawPhone}`;
else if (rawPhone.length === 13 && rawPhone.startsWith('55')) phone_e164 = `+${rawPhone}`;
else if (rawPhone.startsWith('55') && rawPhone.length > 11) phone_e164 = `+${rawPhone}`;

const requiredMissing = [];
if (!rawPhone) requiredMissing.push('phone');
if (!b.nome_negocio) requiredMissing.push('nome_negocio');

const row = {
  phone: rawPhone ? (rawPhone.startsWith('55') ? rawPhone : `55${rawPhone}`) : '',
  phone_e164,
  nome_lead: b.nome_lead || b.nome || '',
  nome_negocio: b.nome_negocio || '',
  bairro: b.bairro || '',
  regiao: b.regiao || '',
  cuisine: b.cuisine || '',
  price_range: b.price_range || '$$',
  rating: String(b.rating || ''),
  tier: b.tier || 'B',
  angulo_copy: Number(b.angulo_copy || 1),
  radar_score_geral: Number(b.radar_score_geral || 0),
  radar_score_reputacao: Number(b.radar_score_reputacao || 0),
  radar_score_digital: Number(b.radar_score_digital || 0),
  radar_score_competitivo: Number(b.radar_score_competitivo || 0),
  radar_score_financeiro: Number(b.radar_score_financeiro || 0),
  radar_oportunidade_min: Number(b.radar_oportunidade_min || 0),
  radar_oportunidade_max: Number(b.radar_oportunidade_max || 0),
  radar_url: b.radar_url || '',
  status: 'novo',
  proximo_touchpoint_id: 'D1_WA',
  proximo_envio_at: new Date().toISOString(),
  metadata: {
    source: b.source || 'webhook-lead-entry',
    tag: b.tag || 'manual_real',
    created_by: 'lead-entry-workflow'
  },
  missing: requiredMissing,
};
return [{ json: row }];
